document.addEventListener("DOMContentLoaded",function(){const e=document.querySelector(".nav__toggle"),t=document.querySelector(".nav__menu");if(e&&t&&e.addEventListener("click",function(){const n=t.classList.toggle("is-open");e.setAttribute("aria-expanded",n)}),document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){e.preventDefault();const t=document.querySelector(this.getAttribute("href"));t&&t.scrollIntoView({behavior:"smooth",block:"start"})})}),"IntersectionObserver"in window){const e=new IntersectionObserver((e,t)=>{e.forEach(e=>{if(e.isIntersecting){const n=e.target;n.src=n.dataset.src||n.src,n.classList.add("is-loaded"),t.unobserve(n)}})});document.querySelectorAll('img[loading="lazy"]').forEach(t=>{e.observe(t)})}})